function every(filter) {
  return (ctx, state) => {
    let i = 0;
    const upds = ctx.messages;
    const max = upds.length;
    const next = () => {
      if (i === max) return true;
      const res = filter(upds[i++], state);
      if (typeof res === "boolean") {
        if (!res) return false;
        return next();
      }
      return res.then((r) => {
        if (!r) return false;
        return next();
      });
    };
    return next();
  };
}
function some(filter) {
  return (ctx, state) => {
    let i = 0;
    const upds = ctx.messages;
    const max = upds.length;
    const next = () => {
      if (i === max) return false;
      const res = filter(upds[i++], state);
      if (typeof res === "boolean") {
        if (res) return true;
        return next();
      }
      return res.then((r) => {
        if (r) return true;
        return next();
      });
    };
    return next();
  };
}
export {
  every,
  some
};
